/* wms-inventory-invnmanager-sql-oracle.xml - updateIvatByLcByUlcAddQty - 재고 속성 변경 및 수량 변경  SQL */

	UPDATE TWORK_INFO_IVATXLCXULC SET
		TTQTY = TTQTY + #{ttqty}
		,AVQTY = AVQTY + #{avqty}
		,ALQTY = ALQTY + #{alqty}
		,PIQTY = PIQTY + #{piqty}
		,PAQTY = PAQTY + #{paqty}
		,HOQTY = HOQTY + #{hoqty}
		,IVATSTATUS = #{ivatstatus}
		,UPDATEDATE = #{sysdate}
		,UPDATEURKEY = #{surkey}
	WHERE CTKEY = #{ctkey}
	    AND IVATKEY = #{ivatkey}
	    AND LCKEY = #{lckey}
	    AND ULCKEY = #{ulckey}
	    AND OWKEY = #{owkey}
	    AND ICKEY = #{ickey}

