/* wms-inventory-invnmanager-sql-oracle.xml - selectIvatByLcByUlcByPk - 재고 속성 PK 조회  SQL */

	SELECT CTKEY, IVATKEY, LCKEY, ULCKEY, OWKEY, ICKEY
		, TTQTY, AVQTY, ALQTY, PIQTY, PAQTY, HOQTY, LOQTY, IVATSTATUS
		, LOGGRPCD
	 FROM TWORK_INFO_IVATXLCXULC
	WHERE CTKEY = #{ctkey}
	    AND IVATKEY = #{ivatkey}
	    AND LCKEY = #{lckey}
	    AND ULCKEY = #{ulckey}
	    AND OWKEY = #{owkey}
	    AND ICKEY = #{ickey}


SELECT A.CTKEY, A.IVATKEY, A.LCKEY, A.ULCKEY, A.OWKEY, A.ICKEY
	, A.TTQTY, A.AVQTY, A.ALQTY, A.PIQTY, A.PAQTY, A.HOQTY, A.IVATSTATUS
 FROM TWORK_INFO_IVATXLCXULC A
 	, TWORK_MST_LC B 


	A.CTKEY = B.CTKEY
	AND A.LCKEY=B.LCKEY
	AND A.TTQTY > 0				
	AND A.CTKEY = #{ctkey}			

		AND A.IVATKEY = #{ivatkey}


		AND A.LCKEY = #{lckey}


		AND A.ULCKEY = #{ulckey}


		AND A.OWKEY = #{owkey}


		AND A.ICKEY = #{ickey}


		AND A.IVATSTATUS = #{ivatstatus}


		AND B.LCHOLDTYPE = #{lcholdtype}

