/* wms-inventory-invnmanager-sql-oracle.xml - updateIvatByLcByUlcIvatStatus - 재고 속성 변경 SQL */

	UPDATE TWORK_INFO_IVATXLCXULC SET
		IVATSTATUS = #{ivatstatus}

		,UPDATEDATE = #{sysdate}
		,UPDATEURKEY = #{surkey}
	WHERE CTKEY = #{ctkey}
	    AND IVATKEY = #{ivatkey}
	    AND LCKEY = #{lckey}
	    AND ULCKEY = #{ulckey}
	    AND OWKEY = #{owkey}
	    AND ICKEY = #{ickey}

mapper.select:
	/* wms-inbound-invnmanager-sql-oracle.xml - selectIvatkeyMap - 재고 속성키 조회 SQL */
		SELECT IVATKEY
		  FROM TWORK_INFO_IVAT 
		 WHERE CTKEY            = #{ctkey}
           AND OWKEY            = #{owkey}
           AND ICKEY            = #{ickey}
           AND EXPIREDATE		= #{expiredate}
           AND UOM				= #{uom}

mapper.insert:
	/* wms-inbound-invnmanager-sql-oracle.xml - insertIvat - 재고 속성 등록  SQL */
    	INSERT INTO TWORK_INFO_IVAT   
		(
		  CTKEY
		, IVATKEY
        , OWKEY
        , ICKEY
        , EXPIREDATE
        , ATTRIBUTE1
        , ATTRIBUTE2
        , IVATSTATUS
        , IBCONFIRMDATE
        , LOGGRPCD
        , CFQTY
        , UOM
        , INSERTDATE
        , INSERTURKEY
        , UPDATEDATE
        , UPDATEURKEY
		)
		VALUES
		(
		  #{ctkey}
		, #{ivatkey}
		, #{owkey}
		, #{ickey}
		, #{expiredate}
		, '2'					/* TC/DC 구분 */
		, '1'					/* 일반/보세 구분  */
		, '10'
		, COALESCE(#{ibconfirmdate}, TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS'))
		, COALESCE(#{loggrpcd}, '1')
		, #{mvqty}
		, #{uom}
		, (TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDDHH24MISS'))
		, #{surkey}
		, (TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDDHH24MISS'))
		, #{surkey}
		)

mapper.update:
	/* wms-inbound-invnmanager-sql-oracle.xml - updateIvat - 재고 수정  SQL */
    	UPDATE TWORK_INFO_IVAT
		   SET CFQTY       = CFQTY + #{mvqty}
		     , UPDATEDATE  = (TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDDHH24MISS'))
		     , UPDATEURKEY = #{surkey}
		 WHERE CTKEY            = #{ctkey}
           AND OWKEY            = #{owkey}
           AND ICKEY            = #{ickey}
           AND EXPIREDATE		= #{expiredate}
           AND UOM				= #{uom}
